    edges.sort((a, b) => a[2] - b[2]);

    // Union-Find data structure
    const parent = Array(n).fill(0).map((_, i) => i);
    const rank = Array(n).fill(0);

    function find(x) {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    function union(x, y) {
        const xRoot = find(x);
        const yRoot = find(y);
        if (xRoot === yRoot) return false;
        if (rank[xRoot] < rank[yRoot]) {
            parent[xRoot] = yRoot;
        } else {
            parent[yRoot] = xRoot;
            if (rank[xRoot] === rank[yRoot]) {
                rank[xRoot]++;
            }
        }
        return true;
    }

    // Initialize the number of connected components
    let components = n;

    // Iterate through edges in order of removal time
    for (const [u, v, time] of edges) {
        // If the edge connects two different components, union them
        if (union(u, v)) {
            components--;
        }
        // Check if we have at least k components
        if (components <= k) {
            return time;
        }
    }

    // If we haven't found a time yet, return 0 (all edges are still present)
    return 0;
