function solve(n, edges, k) {
    // Sort edges by time in ascending order
    edges.sort((a, b) => a[2] - b[2]);

    // Initialize parent array for DSU
    const parent = Array(n).fill(0).map((_, i) => i);

    // Find function with path compression
    function find(u) {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    // Union function
    function union(u, v) {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU !== rootV) {
            parent[rootV] = rootU;
        }
    }

    // Initialize DSU
    for (let i = 0; i < n; i++) {
        parent[i] = i;
    }

    // Count of connected components
    let componentCount = n;

    // Iterate through edges in order of increasing time
    for (const [u, v, time] of edges) {
        // Union the nodes
        union(u, v);

        // Decrease component count if the union was successful
        if (find(u) !== find(v)) {
            componentCount--;
        }

        // If we have enough components, return the current time
        if (componentCount >= k) {
            return time;
        }
    }

    // If we haven't returned yet, return 0 (no edges to remove)
    return 0;
}
