```javascript
function solve(n, edges, k) {
    // Sort edges by their time to process from earliest to latest
    edges.sort((a, b) => a[2] - b[2]);

    // Union-Find (Disjoint Set Union) data structure
    const parent = Array(n).fill(0).map((_, i) => i);
    const rank = Array(n).fill(0);

    function find(x) {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    function union(x, y) {
        const xRoot = find(x);
        const yRoot = find(y);
        if (xRoot === yRoot) return false;
        if (rank[xRoot] < rank[yRoot]) {
            parent[xRoot] = yRoot;
        } else {
            parent[yRoot] = xRoot;
            if (rank[xRoot] === rank[yRoot]) {
                rank[xRoot]++;
            }
        }
        return true;
    }

    let result = 0;
    let components = n;

    for (const [u, v, time] of edges) {
        // If the edge can be removed, remove it by unioning the nodes
        if (union(u, v)) {
            components--;
        }
        // Check if we have at least k components
        if (components <= k) {
            result = time;
        }
    }

    return result;
}
