```javascript
function solve(n, edges, k) {
    // Sort edges by their time to process them in increasing order
    edges.sort((a, b) => a[2] - b[2]);

    // Union-Find data structure to manage connected components
    const parent = Array(n).fill(0).map((_, i) => i);
    const rank = Array(n).fill(0);

    function find(u) {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u, v) {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU !== rootV) {
            if (rank[rootU] > rank[rootV]) {
                parent[rootV] = rootU;
            } else if (rank[rootU] < rank[rootV]) {
                parent[rootU] = rootV;
            } else {
                parent[rootV] = rootU;
                rank[rootU]++;
            }
        }
    }

    let result = 0;
    let components = n;

    for (const [u, v, time] of edges) {
        // Remove the edge by unioning the nodes (this effectively removes the edge)
        union(u, v);
        // Check if the number of components has reached or exceeded k
        if (components >= k) {
            result = time;
            break;
        }
        // If the edge was removed, the number of components increases by 1
        components--;
    }

    // If we didn't find a time where components >= k, return the maximum time
    return result;
}
